module vector_addition (
    input [7:0] x1, // x component of first vector
    input [7:0] y1, // y component of first vector
    input [7:0] x2, // x component of second vector
    input [7:0] y2, // y component of second vector
    output [7:0] x_out, // x component of result vector
    output [7:0] y_out  // y component of result vector
);
      wire _n01 = x1[0] ^ x2[0];
  wire _c01 = x1[0] & x2[0];
  wire _n02 = x1[1] ^ x2[1] ^ _c01;
  wire _c02 = (x1[1] & x2[1]) | (x1[1] & _c01) | (x2[1] & _c01);
  wire _n03 = x1[2] ^ x2[2] ^ _c02;
  wire _c03 = (x1[2] & x2[2]) | (x1[2] & _c02) | (x2[2] & _c02);
  wire _n04 = x1[3] ^ x2[3] ^ _c03;
  wire _c04 = (x1[3] & x2[3]) | (x1[3] & _c03) | (x2[3] & _c03);
  assign x_out = {_n01, _n02, _n03, _n04};
    assign y_out = y1 + y2;
endmodule
